import os
from azure.cosmosdb.sql import CosmosClient, Database, Container
from azure.eventgrid.management.subscription import EventSubscriptionClient
from azure.storage.blob import BlobServiceClient, BlobClient
from azure.identity import DefaultAzureCredential

import azure.functions as func

def main(my_blob_trigger: func.BlobEventTypes, my_blob: func.BlobEventData, out: func.Out[str]):
    if my_blob_trigger == 'blobadded' or my_blob_trigger == 'blobchanged':
        credential = DefaultAzureCredential()
        blob_service_client = BlobServiceClient(credential, os.environ['AZURE_STORAGE_ACCOUNT'])
        cosmos_client = CosmosClient(os.environ['COSMOSDB_ENDPOINT'], os.environ['COSMOSDB_KEY'], credential=credential)
        event_grid_subscription_client = EventSubscriptionClient(credential, os.environ['EVENTGRID_TOPIC'])

        blob_client = blob_service_client.get_blob_client(my_blob.name, my_blob.queue.snapshot_id.container)
        data = blob_client.download_blob().content.decode('utf-8')
        database = cosmos_client.get_database_client("dbname").databases['mydatabase']
        container = database.containers['mycontainer']
        response = container.create_item(data)

        event_grid_event = {
            'topic': os.environ['EVENTGRID_TOPIC'],
            'eventType': 'processingCompleted',
            'data': data,
        }
        event_subscription_client = event_grid_subscription_client.get_subscription('mysubscription')
        event_subscription_client.send(event_grid_event)

        out.set(f'Processed blob "{my_blob.name}"')